starter_code_stages:
#include <stdio.h>
#include <pthread.h>

// ★ Stage 0 — Exemple complet
int data = 42;
pthread_rwlock_t rwlock = PTHREAD_RWLOCK_INITIALIZER; // ★ init statique sans pthread_rwlock_init

int main(void) {
    pthread_rwlock_rdlock(&rwlock);  // ★ acquérir en lecture (partageable)
    printf("Read locked\n");
    printf("data = %d\n", data);
    pthread_rwlock_unlock(&rwlock);  // ★ déverrouiller après lecture
    printf("Read unlocked\n");
    pthread_rwlock_wrlock(&rwlock);  // ★ acquérir en écriture (exclusif)
    printf("Write locked\n");
    data = 100;
    printf("data = %d\n", data);
    pthread_rwlock_unlock(&rwlock);  // ★ déverrouiller après écriture
    printf("Write unlocked\n");
    pthread_rwlock_destroy(&rwlock); // ★ libérer les ressources
    return 0;
}

